SELECT
/*+ INDEX_DESC(B MSP_JUO_SUB_INFO_IDX3) ORDERED USE_NL(A)*/
/*+ INDEX_DESC(B MSP_JUO_SUB_INFO_IDX3) ORDERED USE_NL(A)*/
B.CONTRACT_NUM CONTRACT_NUM, A.SOC, RATE_NM SERVICE_NM, NVL(AGENT_ID, '') AGENT_ID, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, BASIC_REMAINS, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, TO_CHAR(MVNO_BASIC_EXPIRE, 'YYYY-MM-DD') MVNO_BASIC_EXPIRE, TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD') BASIC_EMPT_DT_STR, BASIC_EMPT_DT, B.SUBSCRIBER_NO, B.SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS) SUB_STATUS_NM, B.SUB_LINK_NAME AS SUB_LINK_NAME, SUBSTR(B.LST_COM_ACTV_DATE, 1, 4) || '-' || SUBSTR(B.LST_COM_ACTV_DATE, 5, 2) || '-' || SUBSTR(B.LST_COM_ACTV_DATE, 7, 2) AS LST_COM_ACTV_DATE, TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD') STATUS_STOP_DT, TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD') STATUS_CANCEL_DT, NVL(A.AGENT_SALE_ID,'') AGENT_SALE_ID , F_GET_AGENT_NM(AGENT_SALE_ID) AGENT_SALE_NM, RECHARGE_FLAG, TO_CHAR(STAY_EXPIR_DT, 'YYYY-MM-DD') STAY_EXPIR_DT, TO_CHAR(LAST_BASIC_CHG_DT, 'YYYY-MM-DD') LAST_BASIC_CHG_DT, NVL(D.PAPER_IMAGE, 0) PAPER_IMAGE FROM MSP_JUO_SUB_INFO B, PPS_CUSTOMER A, MSP_RATE_MST C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D WHERE B.CONTRACT_NUM = A.CONTRACT_NUM AND A.SOC = C.RATE_CD AND B.CONTRACT_NUM = D.CONTRACT_NUM(+) AND B.SUB_STATUS IN ('A','S') AND C.PAY_CL_CD = 'PP' AND A.CONTRACT_NUM IS NOT NULL AND B.CUSTOMER_ID IS NOT NULL AND B.SUBSCRIBER_NO IS NOT NULL AND A.CONTRACT_NUM NOT IN (SELECT CONTRACT_NUM FROM PPS_CAN_USR_QUEUE WHERE STATUS NOT IN ('D', 'F1', 'F2', 'S2') )
AND SUBSCRIBER_NO LIKE '%' || #{searchNm} || '%'
AND A.CONTRACT_NUM = #{searchNm}
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND LST_COM_ACTV_DATE >= #{startDt}
AND LST_COM_ACTV_DATE <= #{endDt}
AND D.CONTRACT_NUM IS NOT NULL
AND D.CONTRACT_NUM IS NULL
AND BASIC_EXPIRE >= TO_DATE(#{basicExpireStartDt}, 'YYYYMMDD')
AND BASIC_EXPIRE < TO_DATE(#{basicExpireEndDt}, 'YYYYMMDD')+1
AND MVNO_BASIC_EXPIRE >= TO_DATE(#{mvnoBasicExpireStartDt}, 'YYYYMMDD')
AND MVNO_BASIC_EXPIRE < TO_DATE(#{mvnoBasicExpireEndDt}, 'YYYYMMDD')+1
AND SOC = #{searchSoc}
AND SUB_STATUS = #{searchSubStatus}
AND BASIC_EXPIRE < TRUNC(SYSDATE) + 1 - TO_NUMBER(#{searchExpireCnt})
AND MVNO_BASIC_EXPIRE < TRUNC(SYSDATE) + 1 - TO_NUMBER(#{searchMvnoExpireCnt})
AND BASIC_EMPT_DT < TRUNC(SYSDATE) + 1 - TO_NUMBER(#{searchEmptCnt}) AND LAST_BASIC_CHG_DT < BASIC_EMPT_DT

SELECT
/*+ INDEX_DESC(B MSP_JUO_SUB_INFO_IDX3) ORDERED USE_NL(A)*/
/*+ INDEX_DESC(B MSP_JUO_SUB_INFO_IDX3) ORDERED USE_NL(A)*/
NVL(B.CONTRACT_NUM, '-') CONTRACT_NUM, NVL(A.SOC, '-') SOC, NVL(RATE_NM, '-') SERVICE_NM, NVL(AGENT_ID, '-') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(BASIC_REMAINS, 0) BASIC_REMAINS, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'), '-') BASIC_EXPIRE, NVL(TO_CHAR(MVNO_BASIC_EXPIRE, 'YYYY-MM-DD'), '-') MVNO_BASIC_EXPIRE, NVL(TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD'), '-') BASIC_EMPT_DT_STR, BASIC_EMPT_DT, NVL(B.SUBSCRIBER_NO, '-') SUBSCRIBER_NO, NVL(B.SUB_STATUS, '-') SUB_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS), '-') SUB_STATUS_NM, NVL(B.SUB_LINK_NAME, '-') AS SUB_LINK_NAME, SUBSTR(B.LST_COM_ACTV_DATE, 1, 4) || '-' || SUBSTR(B.LST_COM_ACTV_DATE, 5, 2) || '-' || SUBSTR(B.LST_COM_ACTV_DATE, 7, 2) AS LST_COM_ACTV_DATE, NVL(TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD'), '-') STATUS_STOP_DT, NVL(TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD'), '-') STATUS_CANCEL_DT, NVL(NVL(A.AGENT_SALE_ID,''), '-') AGENT_SALE_ID , NVL(F_GET_AGENT_NM(AGENT_SALE_ID), '-') AGENT_SALE_NM, NVL(RECHARGE_FLAG, '-') RECHARGE_FLAG, NVL(TO_CHAR(STAY_EXPIR_DT, 'YYYY-MM-DD'), '-') STAY_EXPIR_DT, NVL(TO_CHAR(LAST_BASIC_CHG_DT, 'YYYY-MM-DD'), '-') LAST_BASIC_CHG_DT, NVL(D.PAPER_IMAGE, 0) PAPER_IMAGE FROM MSP_JUO_SUB_INFO B, PPS_CUSTOMER A, MSP_RATE_MST C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D WHERE B.CONTRACT_NUM = A.CONTRACT_NUM AND A.SOC = C.RATE_CD AND B.CONTRACT_NUM = D.CONTRACT_NUM(+) AND B.SUB_STATUS IN ('A','S') AND C.PAY_CL_CD = 'PP' AND A.CONTRACT_NUM IS NOT NULL AND B.CUSTOMER_ID IS NOT NULL AND B.SUBSCRIBER_NO IS NOT NULL AND A.CONTRACT_NUM NOT IN (SELECT CONTRACT_NUM FROM PPS_CAN_USR_QUEUE WHERE STATUS NOT IN ('D', 'F1', 'F2', 'S2') )
AND SUBSCRIBER_NO LIKE '%' || #{searchNm} || '%'
AND A.CONTRACT_NUM = #{searchNm}
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND LST_COM_ACTV_DATE >= #{startDt}
AND LST_COM_ACTV_DATE <= #{endDt}
AND D.CONTRACT_NUM IS NOT NULL
AND D.CONTRACT_NUM IS NULL
AND BASIC_EXPIRE >= TO_DATE(#{basicExpireStartDt}, 'YYYYMMDD')
AND BASIC_EXPIRE < TO_DATE(#{basicExpireEndDt}, 'YYYYMMDD')+1
AND MVNO_BASIC_EXPIRE >= TO_DATE(#{mvnoBasicExpireStartDt}, 'YYYYMMDD')
AND MVNO_BASIC_EXPIRE < TO_DATE(#{mvnoBasicExpireEndDt}, 'YYYYMMDD')+1
AND SOC = #{searchSoc}
AND SUB_STATUS = #{searchSubStatus}
AND BASIC_EXPIRE < TRUNC(SYSDATE) + 1 - TO_NUMBER(#{searchExpireCnt})
AND MVNO_BASIC_EXPIRE < TRUNC(SYSDATE) + 1 - TO_NUMBER(#{searchMvnoExpireCnt})
AND BASIC_EMPT_DT < TRUNC(SYSDATE) + 1 - TO_NUMBER(#{searchEmptCnt}) AND LAST_BASIC_CHG_DT < BASIC_EMPT_DT

SELECT
/*+ INDEX_DESC (A PPS_CAN_USR_QUEUE_IDX2)*/
/*+ INDEX_DESC (A PPS_CAN_USR_QUEUE_IDX2)*/
SEQ, GROUP_SEQ, CONTRACT_NUM, CUSTOMER_ID, SUBSCRIBER_NO, SUB_LINK_NAME, STATUS, F_GET_KT_CODE_NM('PPS_CAN_USR_QUEUE','STATUS',STATUS) STATUS_NM, SOC, (SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1)AS SERVICE_NM, SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',SUB_STATUS) SUB_STATUS_NM, BASIC_REMAINS, TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD') BASIC_EMPT_DT, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, TO_CHAR(MVNO_BASIC_EXPIRE, 'YYYY-MM-DD') MVNO_BASIC_EXPIRE, TO_CHAR(LAST_BASIC_CHG_DT, 'YYYY-MM-DD') LAST_BASIC_CHG_DT, TO_CHAR(OPEN_DATE, 'YYYY-MM-DD') OPEN_DATE, TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD') STATUS_STOP_DT, TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD') STATUS_CANCEL_DT, AGENT_ID, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, AGENT_SALE_ID, F_GET_AGENT_NM(AGENT_SALE_ID) AGENT_SALE_NM, REQ_GUBUN, F_GET_KT_CODE_NM('PPS_CAN_USR_QUEUE','REQ_GUBUN',REQ_GUBUN) REQ_GUBUN_NM, REQ_ID, F_GET_ADMIN_NM(REQ_ID) REQ_NM, TO_CHAR(REQ_DT, 'YYYY-MM-DD') REQ_DT, MOD_ID, MOD_DT, CONFIRM_ID, F_GET_ADMIN_NM(CONFIRM_ID) CONFIRM_NM, TO_CHAR(CONFIRM_DT, 'YYYY-MM-DD') CONFIRM_DT, DECODE(STATUS, 'F1', CONN_RSLT_MSG, TCP_RSLT_MSG) RET_MSG, CONN_RSLT_MSG, TCP_RSLT_MSG, REMARK FROM PPS_CAN_USR_QUEUE A WHERE REQ_DT > TO_DATE('20170101', 'YYYYMMDD') AND STATUS <> 'D'
AND CONTRACT_NUM LIKE '%' || #{searchNm} || '%'
AND GROUP_SEQ LIKE '%' || #{searchNm} || '%'
AND SUBSCRIBER_NO LIKE '%' || #{searchNm} || '%'
AND SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND STATUS = #{searchStatus}
AND REQ_DT >= TO_DATE(#{startDt}, 'YYYYMMDD')
AND REQ_DT < TO_DATE(#{endDt}, 'YYYYMMDD')+1
AND REQ_GUBUN = #{searchReqGubun}

SELECT
/*+ INDEX_DESC (A PPS_CAN_USR_QUEUE_IDX2)*/
/*+ INDEX_DESC (A PPS_CAN_USR_QUEUE_IDX2)*/
NVL(SEQ, NULL) SEQ, NVL(GROUP_SEQ, NULL) GROUP_SEQ, NVL(CONTRACT_NUM, NULL) CONTRACT_NUM, NVL(CUSTOMER_ID, '-') CUSTOMER_ID, NVL(SUBSCRIBER_NO, '-') SUBSCRIBER_NO, NVL(SUB_LINK_NAME, '-') SUB_LINK_NAME, NVL(STATUS, '-') STATUS, NVL(F_GET_KT_CODE_NM('PPS_CAN_USR_QUEUE','STATUS',STATUS), '-') STATUS_NM, NVL(SOC, '-') SOC, NVL((SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1), '-') AS SERVICE_NM, NVL(SUB_STATUS, '-') SUB_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',SUB_STATUS), '-') SUB_STATUS_NM, NVL(BASIC_REMAINS, NULL) BASIC_REMAINS, NVL(TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD'), '-') BASIC_EMPT_DT, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'), '-') BASIC_EXPIRE, NVL(TO_CHAR(MVNO_BASIC_EXPIRE, 'YYYY-MM-DD'), '-') MVNO_BASIC_EXPIRE, NVL(TO_CHAR(LAST_BASIC_CHG_DT, 'YYYY-MM-DD'), '-') LAST_BASIC_CHG_DT, NVL(TO_CHAR(OPEN_DATE, 'YYYY-MM-DD'), '-') OPEN_DATE, NVL(TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD'), '-') STATUS_STOP_DT, NVL(TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD'), '-') STATUS_CANCEL_DT, NVL(AGENT_ID, '-') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(AGENT_SALE_ID, '-') AGENT_SALE_ID, NVL(F_GET_AGENT_NM(AGENT_SALE_ID), '-') AGENT_SALE_NM, NVL(REQ_GUBUN, '-') REQ_GUBUN, NVL(F_GET_KT_CODE_NM('PPS_CAN_USR_QUEUE','REQ_GUBUN',REQ_GUBUN), '-') REQ_GUBUN_NM, NVL(REQ_ID, '-') REQ_ID, NVL(F_GET_ADMIN_NM(REQ_ID), '-') REQ_NM, NVL(TO_CHAR(REQ_DT, 'YYYY-MM-DD'), '-') REQ_DT, NVL(CONFIRM_ID, '-') CONFIRM_ID, NVL(F_GET_ADMIN_NM(CONFIRM_ID), '-') CONFIRM_NM, NVL(TO_CHAR(CONFIRM_DT, 'YYYY-MM-DD'), '-') CONFIRM_DT, NVL(DECODE(STATUS, 'F1', CONN_RSLT_MSG, TCP_RSLT_MSG), '-') RET_MSG, NVL(CONN_RSLT_MSG, '-') CONN_RSLT_MSG, NVL(TCP_RSLT_MSG, '-') TCP_RSLT_MSG, NVL(REMARK, '-') REMARK FROM PPS_CAN_USR_QUEUE A WHERE REQ_DT > TO_DATE('20170101', 'YYYYMMDD') AND STATUS <> 'D'
AND CONTRACT_NUM LIKE '%' || #{searchNm} || '%'
AND GROUP_SEQ LIKE '%' || #{searchNm} || '%'
AND SUBSCRIBER_NO LIKE '%' || #{searchNm} || '%'
AND SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND STATUS = #{searchStatus}
AND REQ_DT >= TO_DATE(#{startDt}, 'YYYYMMDD')
AND REQ_DT < TO_DATE(#{endDt}, 'YYYYMMDD')+1
AND REQ_GUBUN = #{searchReqGubun}

{CALL P_PPS_CAN_USR_QUEUE(
			    #{opCode, jdbcType=VARCHAR}
			    , #{param, jdbcType=CLOB}
			    , #{searchEmptCnt, jdbcType=VARCHAR}
			    , #{searchExpireCnt, jdbcType=VARCHAR}
			    , #{searchMvnoExpireCnt, jdbcType=VARCHAR}
			    , #{searchSoc, jdbcType=VARCHAR}
			    , #{searchSubStatus, jdbcType=VARCHAR}
			    , #{startDt, jdbcType=VARCHAR}
			    , #{endDt, jdbcType=VARCHAR}
			    , #{basicExpireStartDt, jdbcType=VARCHAR}
			    , #{basicExpireEndDt, jdbcType=VARCHAR}
			    , #{mvnoBasicExpireStartDt, jdbcType=VARCHAR}
			    , #{mvnoBasicExpireEndDt, jdbcType=VARCHAR}
			    , #{searchPaperImg, jdbcType=VARCHAR} 
			    , #{searchType, jdbcType=VARCHAR}
			    , #{searchNm, jdbcType=VARCHAR}
			    , #{remark, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR}
			   , #{oRetCode, mode=OUT, javaType=string, jdbcType=VARCHAR}
